mapper.select:
SELECT status, COUNT(*) as count FROM task WHERE 1 = 1
AND ( (MOD(#{areaId}, 10000) = 0 AND area_id BETWEEN #{areaId} AND #{areaId} + 9999) OR (MOD(#{areaId}, 10000) != 0 AND MOD(#{areaId}, 100) = 0 AND area_id BETWEEN #{areaId} AND #{areaId} + 99) OR (MOD(#{areaId}, 100) != 0 AND area_id = #{areaId}) )
AND UNIX_TIMESTAMP(public_time) >= #{startTime}
AND UNIX_TIMESTAMP(public_time) <= #{endTime}
GROUP BY status ORDER BY status

SELECT UNIX_TIMESTAMP(DATE(public_time)) as time, COUNT(*) as count FROM task WHERE 1 = 1
AND ( (MOD(#{areaId}, 10000) = 0 AND area_id BETWEEN #{areaId} AND #{areaId} + 9999) OR (MOD(#{areaId}, 10000) != 0 AND MOD(#{areaId}, 100) = 0 AND area_id BETWEEN #{areaId} AND #{areaId} + 99) OR (MOD(#{areaId}, 100) != 0 AND area_id = #{areaId}) )
AND UNIX_TIMESTAMP(public_time) >= #{startTime}
AND UNIX_TIMESTAMP(public_time) <= #{endTime}
GROUP BY time ORDER BY time

SELECT CASE WHEN a.city = '-1' AND a.district = '-1' THEN a.province WHEN a.district = '-1' THEN a.city ELSE a.district END as area_name, COALESCE(COUNT(t.id), 0) as count FROM area a LEFT JOIN task t ON a.id = t.area_id
AND UNIX_TIMESTAMP(t.public_time) >= #{startTime}
AND UNIX_TIMESTAMP(t.public_time) <= #{endTime}
WHERE a.id >= #{startRange} AND a.id <= #{endRange}
AND a.city = '-1' AND a.district = '-1'
AND a.city != '-1' AND a.district = '-1'
AND a.city != '-1' AND a.district != '-1'
AND a.id = #{startRange}
GROUP BY a.id, area_name ORDER BY a.id

SELECT r.id as repairman_id, r.name, CAST(COUNT(t.id) AS CHAR) as data FROM repairman r LEFT JOIN task t ON r.id = t.repairman_id AND t.status = 2
AND ( (MOD(#{areaId}, 10000) = 0 AND t.area_id BETWEEN #{areaId} AND #{areaId} + 9999) OR (MOD(#{areaId}, 10000) != 0 AND MOD(#{areaId}, 100) = 0 AND t.area_id BETWEEN #{areaId} AND #{areaId} + 99) OR (MOD(#{areaId}, 100) != 0 AND t.area_id = #{areaId}) )
AND UNIX_TIMESTAMP(t.public_time) >= #{startTime}
AND UNIX_TIMESTAMP(t.public_time) <= #{endTime}
GROUP BY r.id, r.name ORDER BY COUNT(t.id) DESC, r.id LIMIT 10

SELECT r.id as repairman_id, r.name, CAST(COALESCE(ROUND(AVG(UNIX_TIMESTAMP(t.response_time) - UNIX_TIMESTAMP(t.public_time)) / 3600, 2), 0) AS CHAR) as data FROM repairman r LEFT JOIN task t ON r.id = t.repairman_id AND t.response_time IS NOT NULL
AND ( (MOD(#{areaId}, 10000) = 0 AND t.area_id BETWEEN #{areaId} AND #{areaId} + 9999) OR (MOD(#{areaId}, 10000) != 0 AND MOD(#{areaId}, 100) = 0 AND t.area_id BETWEEN #{areaId} AND #{areaId} + 99) OR (MOD(#{areaId}, 100) != 0 AND t.area_id = #{areaId}) )
AND UNIX_TIMESTAMP(t.public_time) >= #{startTime}
AND UNIX_TIMESTAMP(t.public_time) <= #{endTime}
GROUP BY r.id, r.name HAVING COUNT(t.id) > 0 ORDER BY AVG(UNIX_TIMESTAMP(t.response_time) - UNIX_TIMESTAMP(t.public_time)) ASC, r.id LIMIT 10

SELECT r.id as repairman_id, r.name, CAST(COALESCE(ROUND(AVG(UNIX_TIMESTAMP(t.accomplish_time) - UNIX_TIMESTAMP(t.public_time)) / 3600, 2), 0) AS CHAR) as data FROM repairman r LEFT JOIN task t ON r.id = t.repairman_id AND t.accomplish_time IS NOT NULL AND t.status = 2
AND ( (MOD(#{areaId}, 10000) = 0 AND t.area_id BETWEEN #{areaId} AND #{areaId} + 9999) OR (MOD(#{areaId}, 10000) != 0 AND MOD(#{areaId}, 100) = 0 AND t.area_id BETWEEN #{areaId} AND #{areaId} + 99) OR (MOD(#{areaId}, 100) != 0 AND t.area_id = #{areaId}) )
AND UNIX_TIMESTAMP(t.public_time) >= #{startTime}
AND UNIX_TIMESTAMP(t.public_time) <= #{endTime}
GROUP BY r.id, r.name HAVING COUNT(t.id) > 0 ORDER BY AVG(UNIX_TIMESTAMP(t.accomplish_time) - UNIX_TIMESTAMP(t.public_time)) ASC, r.id LIMIT 10
